{
  "name": "THIRAN Cyberpunk Clone",
  "description": "A high-performance, neon-green and black cyberpunk-themed clone of the Thiran SECE event website, featuring futuristic UI elements and event management mockups."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface EventItem {
  id: string;
  title: string;
  category: 'Technical' | 'Non-Technical' | 'Workshop' | 'Premium';
  description: string;
  prize?: string;
  teamSize?: string;
  image: string;
}

export interface NavItem {
  label: string;
  href: string;
}

export interface Stats {
  label: string;
  value: string;
}

import React, { useState, useEffect } from 'react';
import { NAV_ITEMS } from '../constants';

const Navbar: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${scrolled ? 'bg-black/90 backdrop-blur-md py-4 border-b border-[#00ff41]/30' : 'bg-transparent py-6'}`}>
      <div className="container mx-auto px-4 flex justify-between items-center">
        <div className="flex items-center space-x-2">
          <div className="w-10 h-10 bg-[#00ff41] flex items-center justify-center font-orbitron font-black text-black text-xl rotate-45">
            <span className="-rotate-45">T</span>
          </div>
          <span className="font-orbitron font-black text-2xl tracking-tighter">THIRAN <span className="text-[#00ff41]">2025</span></span>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex space-x-8">
          {NAV_ITEMS.map((item) => (
            <a 
              key={item.label} 
              href={item.href} 
              className="font-orbitron text-sm font-semibold hover:text-[#00ff41] transition-colors relative group"
            >
              {item.label}
              <span className="absolute -bottom-1 left-0 w-0 h-[2px] bg-[#00ff41] transition-all group-hover:w-full"></span>
            </a>
          ))}
        </div>

        <button 
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          className="md:hidden text-[#00ff41] p-2"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            {mobileMenuOpen ? (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" />
            )}
          </svg>
        </button>
      </div>

      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-black border-b border-[#00ff41]/30 py-6 px-4 animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="flex flex-col space-y-4">
            {NAV_ITEMS.map((item) => (
              <a 
                key={item.label} 
                href={item.href} 
                className="font-orbitron text-lg font-bold hover:text-[#00ff41]"
                onClick={() => setMobileMenuOpen(false)}
              >
                {item.label}
              </a>
            ))}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';

const Hero: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });

  useEffect(() => {
    const target = new Date("2025-03-28T00:00:00");
    const interval = setInterval(() => {
      const now = new Date();
      const diff = target.getTime() - now.getTime();

      const d = Math.floor(diff / (1000 * 60 * 60 * 24));
      const h = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const m = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const s = Math.floor((diff % (1000 * 60)) / 1000);

      setTimeLeft({ days: d, hours: h, minutes: m, seconds: s });
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <section id="home" className="relative min-h-screen flex items-center justify-center overflow-hidden cyber-grid">
      {/* Background Animated Elements */}
      <div className="absolute inset-0 z-0 pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-[#00ff41]/5 rounded-full blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-[#00ff41]/5 rounded-full blur-[120px] animate-pulse delay-1000"></div>
      </div>

      <div className="container mx-auto px-4 z-10 text-center">
        <div className="inline-block px-4 py-1 border border-[#00ff41]/50 font-mono text-xs mb-6 tracking-widest text-[#00ff41] animate-bounce">
          SYSTEMS ONLINE // MARCH 28-29, 2025
        </div>

        <h1 className="font-orbitron text-6xl md:text-9xl font-black mb-4 glitch tracking-tighter leading-none">
          THIRAN
        </h1>

        <p className="font-mono text-lg md:text-2xl mb-12 max-w-2xl mx-auto text-gray-400">
          The largest technical symposium of South India. 
          <span className="text-[#00ff41]"> Unleash the innovator within.</span>
        </p>

        <div className="flex flex-wrap justify-center gap-4 mb-16">
          <button className="cyber-border bg-[#00ff41] text-black px-8 py-4 font-orbitron font-bold text-lg hover:bg-white transition-all transform hover:scale-105">
            REGISTER NOW_
          </button>
          <button className="cyber-border border-2 border-[#00ff41] text-[#00ff41] px-8 py-4 font-orbitron font-bold text-lg hover:bg-[#00ff41]/10 transition-all">
            VIEW SCHEDULE
          </button>
        </div>

        {/* Countdown */}
        <div className="flex justify-center space-x-6 md:space-x-12 font-orbitron">
          {[
            { val: timeLeft.days, label: 'DAYS' },
            { val: timeLeft.hours, label: 'HOURS' },
            { val: timeLeft.minutes, label: 'MINS' },
            { val: timeLeft.seconds, label: 'SECS' }
          ].map((item, idx) => (
            <div key={idx} className="flex flex-col items-center">
              <span className="text-4xl md:text-6xl font-black text-[#00ff41]">
                {String(item.val).padStart(2, '0')}
              </span>
              <span className="text-xs md:text-sm font-bold tracking-[0.2em] text-gray-500 mt-2">
                {item.label}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Scroll indicator */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 animate-bounce">
        <svg className="w-6 h-6 text-[#00ff41]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
        </svg>
      </div>
    </section>
  );
};

export default Hero;

import React from 'react';
import { STATS } from '../constants';

const Stats: React.FC = () => {
  return (
    <div className="bg-[#050505] py-16 border-y border-[#00ff41]/20">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
          {STATS.map((stat, idx) => (
            <div key={idx} className="text-center group">
              <div className="font-orbitron text-4xl md:text-5xl font-black text-[#00ff41] mb-2 group-hover:scale-110 transition-transform">
                {stat.value}
              </div>
              <div className="font-mono text-xs md:text-sm tracking-[0.3em] text-gray-500">
                {stat.label}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Stats;

import React, { useState } from 'react';
import { EVENTS } from '../constants';
import { EventItem } from '../types';

const Events: React.FC = () => {
  const [filter, setFilter] = useState<string>('All');
  const categories = ['All', 'Technical', 'Non-Technical', 'Workshop', 'Premium'];

  const filteredEvents = filter === 'All' 
    ? EVENTS 
    : EVENTS.filter(e => e.category === filter);

  return (
    <section id="events" className="py-24 bg-black relative cyber-grid">
      <div className="container mx-auto px-4">
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-8">
          <div>
            <h2 className="font-orbitron text-4xl md:text-6xl font-black">
              EVENT <span className="text-[#00ff41]">MATRIX</span>
            </h2>
            <p className="font-mono text-gray-500 mt-4">Select your protocol and enter the system.</p>
          </div>

          <div className="flex flex-wrap gap-2">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-2 font-orbitron text-xs font-bold transition-all ${
                  filter === cat 
                    ? 'bg-[#00ff41] text-black shadow-[0_0_15px_rgba(0,255,65,0.5)]' 
                    : 'bg-transparent text-[#00ff41] border border-[#00ff41]/30 hover:bg-[#00ff41]/10'
                }`}
              >
                {cat.toUpperCase()}
              </button>
            ))}
          </div>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredEvents.map(event => (
            <EventCard key={event.id} event={event} />
          ))}
        </div>
      </div>
    </section>
  );
};

const EventCard: React.FC<{ event: EventItem }> = ({ event }) => {
  return (
    <div className="group relative bg-[#0a0a0a] border border-[#00ff41]/20 overflow-hidden cyber-border hover:border-[#00ff41]/60 transition-all">
      <div className="h-48 relative overflow-hidden">
        <img 
          src={event.image} 
          alt={event.title}
          className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500 group-hover:scale-110" 
        />
        <div className="absolute top-4 right-4 bg-black/80 backdrop-blur-md px-3 py-1 text-[10px] font-mono border border-[#00ff41]/40">
          {event.category.toUpperCase()}
        </div>
      </div>

      <div className="p-6">
        <h3 className="font-orbitron text-xl font-bold mb-3 group-hover:text-[#00ff41] transition-colors">
          {event.title}
        </h3>
        <p className="font-mono text-sm text-gray-400 mb-6 line-clamp-2">
          {event.description}
        </p>

        <div className="flex items-center justify-between text-xs font-mono">
          <div className="text-gray-500">
            TEAM: <span className="text-white">{event.teamSize}</span>
          </div>
          {event.prize && (
            <div className="text-[#00ff41] font-bold">
              PRIZE: {event.prize}
            </div>
          )}
        </div>

        <button className="w-full mt-6 py-3 bg-[#00ff41]/10 border border-[#00ff41]/40 font-orbitron text-sm font-bold hover:bg-[#00ff41] hover:text-black transition-all">
          EXPLORE_ENTRY
        </button>
      </div>

      {/* Decorative corner */}
      <div className="absolute top-0 left-0 w-8 h-8 border-t-2 border-l-2 border-[#00ff41]/0 group-hover:border-[#00ff41] transition-all"></div>
      <div className="absolute bottom-0 right-0 w-8 h-8 border-b-2 border-r-2 border-[#00ff41]/0 group-hover:border-[#00ff41] transition-all"></div>
    </div>
  );
};

export default Events;

